import banksData from '../data/banks.json';

export interface Bank {
  bin: string;
  code: string;
  name: string;
  fullName: string;
  swiftCode?: string;
}

// Handle potential esModuleInterop/vite differences
const rawBanks = Array.isArray(banksData) ? banksData : (banksData as any).default || [];

// Map the raw JSON data to our Bank interface
export const banks: Bank[] = rawBanks.map((bank: any) => ({
  bin: bank.bin,
  code: bank.code,
  name: bank.name,
  fullName: bank.full_name,
  swiftCode: bank.swift_code
}));
